import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../Context/AuthContext';
import { useCart } from '../Context/CartContext';
import Button from '../Common/Button/Button';
import './CheckoutPage.css';

const CheckoutPage = () => {
    const { user, login } = useAuth();
    const { cart, total, clearCart } = useCart();
    const navigate = useNavigate();

    const [email, setEmail] = useState('');
    const [formData, setFormData] = useState({
        name: '',
        address: '',
        city: '',
        zip: ''
    });
    
    useEffect(() => {
        if (cart.length === 0) {
            navigate('/cart');
        }
    }, [cart, navigate]);
    if (cart.length === 0) {
        return null; 
    }

    

    const handleLogin = (e) => {
        e.preventDefault();
        if (email) login(email);
    };


    
    
    if (!user) {
        return (
            <div className="login-container">
                <h2 className="login-title">Inicia sesión para continuar</h2>
                <div className="login-card">
                    <form onSubmit={handleLogin} className="login-form">
                        <input
                            type="email"
                            placeholder="Tu correo electrónico"
                            value={email}
                            onChange={(e) => setEmail(e.target.value)}
                            required
                            className="login-input"
                        />
                        <button type="submit" className="btn-primary">
                            Continuar como Invitado
                        </button>
                    </form>
                    <p className="login-note">
                        (Simulación: ingresa cualquier correo)
                    </p>
                    <p className="login-note">
                        (Simulación: ingresa la contraseña "12345")
                    </p>
                </div>
            </div>
        );
    }

    return (
        <div className="checkout-container">
            <h1 className="checkout-title">Checkout</h1>

            <div className="checkout-layout">
                <div>
                    <div className="checkout-section">
                        <SummarySection
                            title="1. Dirección de envío"
                            selected={selectedAddress}
                            summaryContent={
                                <div className="selected-address">
                                    <p>{selectedAddress?.name}</p>
                                    <p>{selectedAddress?.address1}</p>
                                    <p>{selectedAddress?.city}, {selectedAddress?.postalCode}</p>
                                </div>
                            }
                            isExpanded={
                                showAddressForm || addressSectionOpen || !selectedAddress
                            }
                            onToggle={handleAddressToggle}
                        >
                        {!showAddressForm && !editingAddress ? (
                        <AddressList
                            addresses={addresses}
                            selectedAddress={selectedAddress}
                            onSelect={handleSelectAddress}
                            onEdit={handleAddressEdit}
                            onAdd={handleAddressNew}
                            onDelete={handleAddressDelete}
                        />
                    ) : (
                        <AddressForm
                            onSubmit={handleAddressSubmit}
                            onCancel={handleCancelAddress}
                            initialValues={editingAddress || {}}
                            isEdit={!!editingAddress}
                        />
                    )}
                </SummarySection>

                <SummarySection
                    title="2. Método de pago"
                    selected={selectedPayment}
                    summaryContent={
                        <div className="selected-payment">
                            <p>{selectedPayment?.alias}</p>
                            <p>**** {selectedPayment?.cardNumber?.slice(-4) || "----"}</p>
                        </div>
                    }
                    isExpanded={
                    showPaymentForm || paymentSectionOpen || !selectedPayment
                    }
                    onToggle={handlePaymentToggle}
                >
                    {!showPaymentForm && !editingPayment ? (
                        <PaymentList
                            payments={payments}
                            selectedPayment={selectedPayment}
                            onSelect={handleSelectPayment}
                            onEdit={handlePaymentEdit}
                            onAdd={handlePaymentNew}
                            onDelete={handlePaymentDelete}
                        />
                    ) : (
                        <PaymentForm
                            onSubmit={handlePaymentSubmit}
                            onCancel={handleCancelPayment}
                            initialValues={editingPayment || {}}
                            isEdit={!!editingPayment}
                        />
                    )}
                </SummarySection>

                <SummarySection
                    title="3. Revisa tu pedido"
                    selected={true}
                    isExpanded={true}
                >
                    <CartView />
                </SummarySection>
            </div>
        </div>

                    <div className="checkout-section">
                        <h3 className="section-title">2. Pago</h3>
                        <div className="payment-placeholder">
                            Simulación de pago (No se requiere tarjeta real)
                        </div>
                    </div>
                </div>

                <div>
                    <div className="checkout-summary">
                        <h3 className="summary-title">Resumen</h3>
                        {cart.map(item => (
                            <div key={item.id} className="summary-item">
                                <span>{item.quantity}x {item.name}</span>
                                <span>${(item.price * item.quantity).toFixed(2)}</span>
                            </div>
                        ))}
                        <div className="summary-total">
                            <span>Total</span>
                            <span className="total-amount">${total.toFixed(2)}</span>
                        </div>

                        <p>
                            <strong>Fecha estimada de entrega:</strong>{" "}
                            {new Date(
                                Date.now() + 7 * 24 * 60 * 60 * 1000
                            ).toLocaleDateString()}
                        </p>
                    </div>
                    <Button
                            className="pay-button"
                            disabled={
                                !selectedAddress ||
                                !selectedPayment ||
                                !cartItems ||
                                cartItems.length === 0
                            }
                            title={
                                !cartItems || cartItems.length === 0
                                    ? "No hay productos en el carrito"
                                    : !selectedAddress
                                    ? "Selecciona una dirección de envío"
                                    : !selectedPayment
                                    ? "Selecciona un método de pago"
                                    : "Confirmar y realizar el pago"
                            }
                            onClick={handleCreateOrder}
                        >
                            Confirmar y Pagar
                        </Button>
                </div>
        </div>
    );
};

export default CheckoutPage;
